mapper.select:
SELECT DISTINCT t.id, t.slug, t.name, t.description, COUNT(tb2.book_id) AS overlapCount FROM special_topic_book tb1 INNER JOIN special_topic_book tb2 ON tb1.book_id = tb2.book_id INNER JOIN special_topic t ON t.id = tb2.topic_id WHERE tb1.topic_id = #{topicId} AND tb2.topic_id != #{topicId} AND t.enabled = 1
AND tb1.book_id = #{bookId}
GROUP BY t.id, t.slug, t.name, t.description ORDER BY overlapCount DESC, t.id DESC LIMIT 8

SELECT t.id AS topicId, t.slug, t.name, COUNT(DISTINCT tb.book_id) AS bookCount, COUNT(DISTINCT f.user_id) AS favoriteUsers, COUNT(DISTINCT CONCAT(f.user_id, '_', f.book_id)) AS favoriteActions, COUNT(s.id) AS shareCount, DATE_FORMAT(MAX(s.created_at), '%Y-%m-%d %H:%i:%s') AS lastShareAt FROM special_topic t LEFT JOIN special_topic_book tb ON tb.topic_id = t.id LEFT JOIN topic_book_favorite f ON f.topic_id = t.id LEFT JOIN topic_share_log s ON s.topic_id = t.id WHERE t.enabled = 1
AND t.id = #{topicId}
GROUP BY t.id, t.slug, t.name ORDER BY t.id DESC
